const bridgeOutput = $input.first().json;
const out = bridgeOutput.output || '';

// Detect silent failures of Claude Bridge that return HTTP 200 with bad content:
// - OAuth expired: "Not logged in - Please run /login"
// - Output truncated/empty: legitimate brief is typically >100 chars
const oauthDead = /not logged in|please run \/login|please log in/i.test(out);
const tooShort = out.trim().length < 30;

if (out.length > 10 && !oauthDead && !tooShort) {
  return [{ json: { output: out, elapsed_s: bridgeOutput.elapsed_s || 0, fallback: false, prompt: '' } }];
}

const prompt = $('Build Prompt').first().json.prompt || '';
return [{ json: { output: '', elapsed_s: 0, fallback: true, prompt: prompt } }];

