const output = $json.output;
const elapsed = $json.elapsed_s;
const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

let text = output
  .replace(/^### (.+)$/gm, '*$1*')
  .replace(/^## (.+)$/gm, '*$1*')
  .replace(/^# (.+)$/gm, '*$1*')
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

text = `📋 Daily Brief — ${date}\n\n${text}\n\n───\n⏱️ Gerado em ${elapsed}s via Claude Code (with memory)`;

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const response = $input.first().json;
const text = response.content && response.content[0] ? response.content[0].text : JSON.stringify(response);
return [{ json: { output: text + '\n\n⚠️ Gerado via Haiku API (fallback — Claude Bridge indisponivel)', elapsed_s: 0 } }];

// ===== HELPERS =====
function getTaskName(item) {
  const props = item.json.properties || {};
  const nameProps = ['Name', 'Task', 'Title', 'name', 'title'];
  for (const key of nameProps) {
    if (props[key] && props[key].title && Array.isArray(props[key].title) && props[key].title.length > 0) {
      return props[key].title.map(t => t.plain_text || '').join('').trim();
    }
  }
  for (const key of Object.keys(props)) {
    const p = props[key];
    if (p && p.type === 'title' && Array.isArray(p.title) && p.title.length > 0) {
      return p.title.map(t => t.plain_text || '').join('').trim();
    }
  }
  return '(sem nome)';
}

function getTags(item) {
  const props = item.json.properties || {};
  const tagProps = ['Tags', 'Tag', 'Labels'];
  for (const key of tagProps) {
    if (props[key]) {
      if (props[key].multi_select) return props[key].multi_select.map(t => t.name);
      if (props[key].select && props[key].select.name) return [props[key].select.name];
    }
  }
  return [];
}

function getDueDate(item) {
  const props = item.json.properties || {};
  const dateProps = ['Due Date', 'Due', 'Date', 'Deadline'];
  for (const key of dateProps) {
    if (props[key] && props[key].date && props[key].date.start) {
      return props[key].date.start;
    }
  }
  return '';
}

// FIX #1: Resolver Project relation → nome real via lookup local
function getProjectId(item) {
  const props = item.json.properties || {};
  const projProps = ['Project', 'Projects'];
  for (const key of projProps) {
    if (props[key] && props[key].relation && props[key].relation.length > 0) {
      return props[key].relation[0].id;
    }
  }
  return '';
}

function getProjectType(item) {
  const props = item.json.properties || {};
  const typeProps = ['Type', 'Tipo', 'Category'];
  for (const key of typeProps) {
    if (props[key]) {
      if (props[key].select && props[key].select.name) return props[key].select.name;
    }
  }
  return '';
}

// FIX #5: Geo/contexto a partir das tags
function getContext(tags) {
  if (tags.includes('Brasil')) return '🇧🇷';
  if (tags.includes('Portugal')) return '🇵🇹';
  return '';
}

function getDependency(tags) {
  if (tags.includes('Dependo de Terceiros')) return '⏸️';
  return '';
}

// FIX #2: Forçar timezone Europe/Lisbon — usa Intl API (sempre disponível, sem dependências)
function getTodayLisbon() {
  const now = new Date();
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });
  return fmt.format(now); // YYYY-MM-DD
}

function getWeekdayLisbon() {
  const now = new Date();
  const fmt = new Intl.DateTimeFormat('pt-PT', {
    timeZone: 'Europe/Lisbon',
    weekday: 'long'
  });
  const day = fmt.format(now).toLowerCase();
  // Capitalizar primeira letra, remover acentos para evitar problemas downstream
  const map = {
    'domingo': 'Domingo',
    'segunda-feira': 'Segunda',
    'terça-feira': 'Terca',
    'quarta-feira': 'Quarta',
    'quinta-feira': 'Quinta',
    'sexta-feira': 'Sexta',
    'sábado': 'Sabado'
  };
  return map[day] || day;
}

// ===== GET YESTERDAY DAILY SUMMARY =====
let yesterdaySummary = '';
try {
  const summaryNode = $('Get Yesterday Summary').first().json;
  if (summaryNode && summaryNode.found && summaryNode.entries && summaryNode.entries.length > 0) {
    const entry = summaryNode.entries[0];
    const dateTag = (entry.tags || []).find(t => /^\d{4}-\d{2}-\d{2}$/.test(t)) || 'data desconhecida';
    yesterdaySummary = `\n\nDAILY SUMMARY DE ONTEM (${dateTag}):\n${entry.details || entry.summary}\n`;
  } else {
    yesterdaySummary = '\n\n(Sem daily summary de ontem disponivel — primeira sessao ou dia anterior sem fecho)\n';
  }
} catch(e) {
  yesterdaySummary = '\n\n(Erro a obter daily summary de ontem)\n';
}

